// Prepare message with video info and approval buttons
const info = $node["Extract Video Metadata"].json;
const maxRetries = 3;

const retryInfo = info.attemptNumber > 1 
 ? `\n🔄 *Attempt ${info.attemptNumber}/${maxRetries}* (previous declined)`
 : '';

const caption = `🎬 *Historical Video*${retryInfo}

📅 *Event:* ${info.eventDescription.substring(0, 150)}
🗓️ *Year:* ${info.eventYear}

📝 *Script:*
${info.script.substring(0, 200)}${info.script.length > 200 ? '...' : ''}

❓ *Upload to YouTube?*
/yes - Upload this video
/no - Try another event
/stop - Stop workflow`;

return { 
 caption: caption,
 videoUrl: info.videoUrl,
 eventYear: info.eventYear,
 eventDescription: info.eventDescription,
 script: info.script,
 attemptNumber: info.attemptNumber
};

const maxRetries = 3;

// Get current retry count from input data
const current = $input.first().json.retryCount || 0;

// Increment retry
const next = current + 1;

// Check if limit reached (>= means stop when attempts exceed maxRetries)
if (next >= maxRetries) {
 return {
 stopWorkflow: true,
 message: `⛔ Max retries (${maxRetries}) reached. Workflow stopped after ${next} attempts.`,
 retryCount: next,
 attemptNumber: next
 };
}

return {
 stopWorkflow: false,
 retryCount: next,
 attemptNumber: next,
 message: `🔄 Retry ${next}/${maxRetries} - selecting a new historical event`
};

// Send final confirmation after successful YouTube upload
const uploadResult = $input.first().json;
const videoInfo = $node["Extract Video Metadata"].json;

const message = `✅ *Video uploaded to YouTube!*

📹 *Watch:* https://www.youtube.com/watch?v=${uploadResult.id}
📅 *Event:* ${videoInfo.eventDescription.substring(0, 100)}
🗓️ *Year:* ${videoInfo.eventYear}`;

return { message: message };

// Pick a random historical event from the fetched data
const data = $input.first().json.data;
const events = data.Events;

// Random selection - each run picks a different event
const selectedEvent = events[Math.floor(Math.random() * events.length)];

// Clean HTML entities from event description
const cleanText = selectedEvent.text
 .replace(/&nbsp;/g, ' ')
 .replace(/&[a-z]+;/g, ' ')
 .replace(/\s+/g, ' ')
 .trim();

// Get retry count from input if available
const retryData = $input.first().json;
const retryCount = retryData.retryCount || 0;
const attemptNumber = retryCount + 1;

return {
 year: selectedEvent.year,
 description: cleanText,
 retryCount: retryCount,
 attemptNumber: attemptNumber
};

// Extract video URL and metadata from fal.ai response
const response = $input.first().json;
const videoFile = response.video;
const eventInfo = $node["Select Random Historical Event"].json;

if (!videoFile || !videoFile.url) {
 throw new Error('No video URL found from fal.ai');
}

return {
 videoUrl: videoFile.url,
 eventYear: eventInfo.year,
 eventDescription: eventInfo.description,
 script: $node["Generate Cinematic Script with AI"].json.output,
 retryCount: eventInfo.retryCount,
 attemptNumber: eventInfo.attemptNumber
};

// Initialize workflow state for retry tracking
// Using a robust approach that passes data through the flow

// Check if we have incoming retry data
const input = $input.first();
let retryCount = 0;

if (input && input.json) {
 // If this is a retry, preserve the retry count
 if (input.json.retryCount !== undefined) {
 retryCount = input.json.retryCount;
 }
}

// For fresh starts, retryCount remains 0
return {
 retryCount: retryCount,
 attemptNumber: retryCount + 1,
 stopWorkflow: false,
 initialized: true,
 message: retryCount > 0 ? `Continuing with retry attempt ${retryCount + 1}` : "Workflow initialized"
};
